@Component
public class ConsumerKafka {
    @KafkaListener(topics = "my-topic", groupId = "mygroup")
    public void receiveEvent(String in) throws Exception {
        System.out.printf("#### -> Consumed message -> %s \n", in);

    }

    @PostConstruct() //This is a required annotation to listen messages with this spring boot application
    public void initialize() throws IOException{
        InputStream stream = getClass().getResourceAsStream("/application.properties");
        Properties props = new Properties();
        props.load(stream);

        List<String> topicsList = Arrays.asList("my-topic"); //Add here your topic that you want to consume from.

        KafkaConsumer consumer = new KafkaConsumer<>(props, null, null);
        consumer.subscribe(topicsList);

        while (true) {
            ConsumerRecords<Object, Object> records = consumer.poll(100);

            for (ConsumerRecord record : records){
                System.out.printf("Topic:%s, Partition:%d, offset:%d, key: %s \n",
                        record.topic(),record.partition(), record.offset(),record.key());
            }
        }
    }

}

@Component
public class ProducerKafka {

    @Value("${spring.kafka.producer.bootstrap-servers}") //This is your broker URL
    private String bootstrap_server;

    public void sendMessage(String topic, String message) throws Exception{

        Properties props = new Properties();
        props.put("bootstrap.servers", bootstrap_server); //This is your broker URL
        Producer<Object, Object> producer = new KafkaProducer<>(props, null, null);

        for (int i = 0; i <1 ; i++) {
            System.out.printf(i + "\n");

            String msg = message + i;//The message that you want to send to kafka topic

            ProducerRecord<Object, Object> record = new ProducerRecord<>(topic,
                    null/*Partition will be selected by the producer*/,
                    msg);


            producer.send(record);//This is how a message is sent on a certain topic
            //producer.flush(); //You need this because otherwise this producer is not able to send the messages
        }

        Thread.sleep(100);
    }

    public static void main(String[] args) throws Exception {


        Properties props = new Properties();//This is your broker URL
        String bootstrap_server ="localhost:9092";
        props.put("bootstrap.servers", bootstrap_server);//This is the Kafka bootstrap address where it listens for consumers and producers to connect

        Producer<Object, Object> producer = new KafkaProducer<>(props); //This is a Kafka Producer

        for (int i= 1; i <5 ;i++) {
            Thread.sleep(2000);//We have a delay of 2 seconds so that we can read the message

            String msg ="This is message number " + i;//The message that you want to send to kafka topic


            ProducerRecord<Object, Object> record = new ProducerRecord("my-topic", null/*Partition will be selected by the producer*/,msg);
            //This is a Kafka Producer Record. Here we can see that it is being sent on my_topic Topic

            System.out.printf(i + "\n");//This is how we print the message and show that it is being produced
            System.out.println("Topic:" + record.topic() + " Partition:" +record.partition()+  "Offset:"
                    + record.offset()+"Key:"+record.key()); //This is how a message is sent on a certain topic
            producer.send(record);//This is how a message is sent on a certain topic

            Thread.sleep(100);
        }

        producer.flush();//You need this because otherwise this producer is not able to send the messages
    }
}

